PRAGMA foreign_keys=OFF;

DROP TABLE armor;
DROP TABLE armor_recipe;
DROP TABLE armor_skill;
DROP TABLE weapon;
DROP TABLE weapon_parent;
DROP TABLE weapon_recipe;

CREATE TABLE `armor` (`id` INTEGER NOT NULL, `armor_set_id` INTEGER NOT NULL, `armor_type` TEXT NOT NULL, `hunter_type` TEXT NOT NULL, `gender` TEXT NOT NULL, `rarity` INTEGER NOT NULL, `price` INTEGER NOT NULL, `num_slots` INTEGER NOT NULL, `defense` INTEGER NOT NULL, `max_defense` INTEGER NOT NULL, `fire_res` INTEGER NOT NULL, `water_res` INTEGER NOT NULL, `thunder_res` INTEGER NOT NULL, `ice_res` INTEGER NOT NULL, `dragon_res` INTEGER NOT NULL, PRIMARY KEY(`id`), FOREIGN KEY(`armor_set_id`) REFERENCES `armor_set`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE TABLE `armor_recipe` (`armor_id` INTEGER NOT NULL, `item_id` INTEGER NOT NULL, `quantity` INTEGER NOT NULL, `recipe_variant` INTEGER NOT NULL, PRIMARY KEY(`armor_id`, `item_id`, `recipe_variant`), FOREIGN KEY(`armor_id`) REFERENCES `armor`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION , FOREIGN KEY(`item_id`) REFERENCES `item`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE TABLE `armor_skill` (`armor_id` INTEGER NOT NULL, `skill_tree_id` INTEGER NOT NULL, `point_value` INTEGER NOT NULL, PRIMARY KEY(`armor_id`, `skill_tree_id`), FOREIGN KEY(`armor_id`) REFERENCES `armor`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION , FOREIGN KEY(`skill_tree_id`) REFERENCES `skill_tree`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE TABLE `weapon` (`id` INTEGER NOT NULL, `weapon_type` TEXT NOT NULL, `rarity` INTEGER NOT NULL, `affinity` INTEGER NOT NULL, `defense` INTEGER NOT NULL, `num_slots` INTEGER NOT NULL, `attack` INTEGER NOT NULL, `max_attack` INTEGER, `price` INTEGER NOT NULL, `element_1` TEXT, `element_1_value` INTEGER, `element_2` TEXT, `element_2_value` INTEGER, `sharpness` TEXT, `sharpness_plus` TEXT, `shelling_type` TEXT, `shelling_level` INTEGER, `song_notes` TEXT, `reload_speed` TEXT, `recoil` TEXT, `buildable` INTEGER NOT NULL, PRIMARY KEY(`id`));
CREATE TABLE `weapon_parent` (`weapon_id` INTEGER NOT NULL, `parent_weapon_id` INTEGER NOT NULL, PRIMARY KEY(`weapon_id`, `parent_weapon_id`), FOREIGN KEY(`weapon_id`) REFERENCES `weapon`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION , FOREIGN KEY(`parent_weapon_id`) REFERENCES `weapon`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE TABLE `weapon_recipe` (`weapon_id` INTEGER NOT NULL, `item_id` INTEGER NOT NULL, `quantity` INTEGER NOT NULL, `recipe_type` TEXT NOT NULL, `recipe_variant` INTEGER NOT NULL, PRIMARY KEY(`weapon_id`, `item_id`, `recipe_type`, `recipe_variant`), FOREIGN KEY(`weapon_id`) REFERENCES `weapon`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION , FOREIGN KEY(`item_id`) REFERENCES `item`(`id`) ON UPDATE NO ACTION ON DELETE NO ACTION );

